module RefModule(
  input clk,
  input reset_n,
  input din,
  output dout
);parameter depth = 2;

reg [depth-1:0] obf_ff;
reg [depth-1:0] ff_next;

always @(posedge clk or negedge reset_n) begin
  if (~reset_n) begin
    obf_ff <= {depth{1'b0}};
  end else begin
    obf_ff <= {obf_ff[depth-2:0], din};
  end
end

assign dout = obf_ff[depth-1];

endmodule
